/* Enable standard and discretionary ligatures, and old-style figures */
.prose-content {
  font-feature-settings: "liga" 1, "dlig" 1, "onum" 1;
}

/* Or use the preferred method for small caps */
.small-caps-text {
  font-variant-caps: small-caps;
  /* Fallback/alternative using font-feature-settings if font-variant-caps is not sufficient */
  /* font-feature-settings: "smcp" 1; */
}

.stylistic-set-1 {
  font-feature-settings: "ss01" 1;
}
